define i32 @n4(i32 %x, i32 %y) {
  %t0 = xor i32 %x, -1
  %t1 = sub i32 %t0, %y
  ret i32 %t1
}

define i32 @n5_is_not_not(i32 %x, i32 %y) {
  %t0 = xor i32 %x, 2147483647
  %t1 = sub i32 %y, %t0
  ret i32 %t1
}

define i32 @p0_scalar(i32 %x, i32 %y) {
  %t0 = xor i32 %x, -1
  %t1 = sub i32 %y, %t0
  ret i32 %t1
}

define i8 @p0_scalar_not_truly_negatable(i8 %x, i8 %y) {
  %xx = xor i8 %x, 123
  %yy = xor i8 %y, 45
  %r = sub i8 %xx, %yy
  ret i8 %r
}
